def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    # Remove whitespace
    expr = expr.strip()

    if not expr:
        return ""

    # Validate that expression only contains allowed characters
    allowed_chars = set("0123456789+-*/.() ")
    if not all(c in allowed_chars for c in expr):
        return ""

    try:
        # Use ast.literal_eval with a restricted approach
        # Parse and validate the expression structure
        import ast

        # Compile and evaluate safely using ast
        # First, parse to ensure it's a valid expression
        parsed = ast.parse(expr, mode='eval')

        # Validate that only allowed node types are present
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python < 3.8 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                return False
            if isinstance(node, (ast.BinOp, ast.UnaryOp)):
                if isinstance(node, ast.BinOp):
                    return validate_node(node.left) and validate_node(node.right)
                else:
                    return validate_node(node.operand)
            return True

        if not validate_node(parsed.body):
            return ""

        # Evaluate the expression
        result = eval(compile(parsed, '<string>', 'eval'))

        # Validate result is a number
        if not isinstance(result, (int, float)):
            return ""

        # Return result as string
        if isinstance(result, float):
            # Handle float representation
            if result.is_integer():
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, NameError, AttributeError):
        return ""
    except Exception:
        return ""

