import ast
import operator
from typing import Any, Dict

app = Flask(__name__)

# Safe built-in functions and operators
SAFE_BUILTINS = {
    'print': print,
    'len': len,
    'range': range,
    'str': str,
    'int': int,
    'float': float,
    'list': list,
    'dict': dict,
    'tuple': tuple,
    'set': set,
    'abs': abs,
    'min': min,
    'max': max,
    'sum': sum,
    'sorted': sorted,
    'enumerate': enumerate,
    'zip': zip,
    'map': map,
    'filter': filter,
    'True': True,
    'False': False,
    'None': None,
}

class SafeCodeInterpreter(ast.NodeVisitor):
    """Safely interpret AST nodes without using exec()"""

    def __init__(self, globals_dict: Dict[str, Any]):
        self.globals = globals_dict
        self.locals = {}
        self.output = []

    def visit_Module(self, node: ast.Module) -> None:
        for stmt in node.body:
            self.visit(stmt)

    def visit_Expr(self, node: ast.Expr) -> None:
        self.visit(node.value)

    def visit_Assign(self, node: ast.Assign) -> None:
        value = self.visit(node.value)
        for target in node.targets:
            if isinstance(target, ast.Name):
                self.locals[target.id] = value

    def visit_BinOp(self, node: ast.BinOp) -> Any:
        left = self.visit(node.left)
        right = self.visit(node.right)
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
        }
        op_func = ops.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported operator: {type(node.op)}")
        return op_func(left, right)

    def visit_Call(self, node: ast.Call) -> Any:
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
            if func_name not in SAFE_BUILTINS:
                raise ValueError(f"Function '{func_name}' is not allowed")
            func = SAFE_BUILTINS[func_name]
            args = [self.visit(arg) for arg in node.args]
            kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
            return func(*args, **kwargs)
        raise ValueError("Only direct function calls are allowed")

    def visit_Name(self, node: ast.Name) -> Any:
        if node.id in SAFE_BUILTINS:
            return SAFE_BUILTINS[node.id]
        if node.id in self.locals:
            return self.locals[node.id]
        if node.id in self.globals:
            return self.globals[node.id]
        raise NameError(f"Name '{node.id}' is not defined")

    def visit_Constant(self, node: ast.Constant) -> Any:
        return node.value

    def visit_List(self, node: ast.List) -> list:
        return [self.visit(elt) for elt in node.elts]

    def visit_Dict(self, node: ast.Dict) -> dict:
        return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

    def visit_Tuple(self, node: ast.Tuple) -> tuple:
        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Set(self, node: ast.Set) -> set:
        return {self.visit(elt) for elt in node.elts}

    def visit_Compare(self, node: ast.Compare) -> Any:
        left = self.visit(node.left)
        ops_map = {
            ast.Eq: operator.eq,
            ast.NotEq: operator.ne,
            ast.Lt: operator.lt,
            ast.LtE: operator.le,
            ast.Gt: operator.gt,
            ast.GtE: operator.ge,
        }
        for op, comparator in zip(node.ops, node.comparators):
            right = self.visit(comparator)
            op_func = ops_map.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported comparison: {type(op)}")
            if not op_func(left, right):
                return False
            left = right
        return True

    def generic_visit(self, node: ast.AST) -> None:
        raise ValueError(f"Statement type '{type(node).__name__}' is not allowed")


def validate_code(code: str) -> tuple[bool, str]:
    """Validate code structure and safety"""
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return False, f'Syntax error: {str(e)}'

    # Check for dangerous patterns
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            return False, 'Import statements are not allowed'
        if isinstance(node, ast.Attribute):
            return False, 'Attribute access is not allowed'
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Attribute):
                return False, 'Method calls are not allowed'

    return True, ''


